import React, { useState } from 'react';
import './SchedulePage.css';

export default function SchedulePage() {
  const [activeTab, setActiveTab] = useState('sop');

  const tabs = ['sop', 'jadwal', 'silabus', 'materi'];

  return (
    <>
      {/* HEADER */}
      <section className="page-header">
        <div className="container">
          <h1>Praktikum</h1>
          <p>Informasi lengkap praktikum</p>
        </div>
      </section>

      {/* SECTION PRAKTIKUM */}
      <section className="praktikum-section">
        <div className="container">

          {/* BUTTON ATAS */}
          <div className="top-actions">
            <button className="btn-main">Daftar Praktikum</button>
            <button className="btn-main outline">Daftar Ulang</button>
          </div>

          {/* TAB MENU */}
          <div className="tab-menu">
            {tabs.map(tab => (
              <button
                key={tab}
                className={`tab-btn ${activeTab === tab ? 'active' : ''}`}
                onClick={() => setActiveTab(tab)}
              >
                {tab.toUpperCase()}
              </button>
            ))}
          </div>

          {/* CONTENT */}
          <div className="tab-content">
            {activeTab === 'sop' && (
              <div>
                <h2>Content SOP</h2>
                <p>Isi SOP praktikum di sini...</p>
              </div>
            )}

            {activeTab === 'jadwal' && (
              <div>
                <h2>Jadwal Praktikum</h2>
                <p>Isi jadwal di sini...</p>
              </div>
            )}

            {activeTab === 'silabus' && (
              <div>
                <h2>Silabus</h2>
                <p>Isi silabus di sini...</p>
              </div>
            )}

            {activeTab === 'materi' && (
              <div>
                <h2>Unduh Materi</h2>
                <p>List download materi...</p>
              </div>
            )}
          </div>

        </div>
      </section>
    </>
  );
}
